func FuzzDecodeMemoryCeiling(f *testing.F) {
	seed := New(1, math.MaxInt64, 5)
	if enc, err := seed.Encode(V2CompressedEncodingCookieBase); err == nil {
		f.Add(enc)
	}
	small := New(1, 1000000, 3)
	_ = small.RecordValue(42)
	if enc, err := small.Encode(V2CompressedEncodingCookieBase); err == nil {
		f.Add(enc)
	}
	const maxInputForCeiling = 4096
	const allocCeiling = 8 << 20 // 8 MB
	f.Fuzz(func(t *testing.T, encoded []byte) {
		if len(encoded) > maxInputForCeiling {
			return
		}
		runtime.GC()
		var m1, m2 runtime.MemStats
		runtime.ReadMemStats(&m1)
		rh, err := Decode(encoded)
		runtime.ReadMemStats(&m2)
		if err != nil || rh == nil {
			return
		}
		delta := int64(m2.TotalAlloc - m1.TotalAlloc)
		if delta > allocCeiling {
			t.Fatalf("decode-alloc amplification: %d-byte input allocated %d bytes (%.1f MB), countsLen=%d",
				len(encoded), delta, float64(delta)/(1<<20), rh.countsLen)
		}
	})
}

